import { useEffect, useState } from 'react'

import { Link } from 'react-router-dom'

import { FitnessCenter as FitnessCenterIcon } from '@mui/icons-material'
import {
  Container,
  Typography,
  Box,
  Paper,
  List,
  ListItem,
  ListItemButton,
  ListItemIcon,
  ListItemText,
  CircularProgress,
  Chip,
} from '@mui/material'

import { getTrainingPlans } from '@/api/trainingPlans'
import { LoginButton } from '@/components/LoginButton'
import { useAuth } from '@/contexts/AuthContext'
import { routes } from '@/routes'
import type { TrainingPlan } from '@/types/database'
import { getTodaysPlans, getWeekDayLabel } from '@/utils/schedule'

export function HomePage() {
  const { user } = useAuth()
  const [todaysPlans, setTodaysPlans] = useState<TrainingPlan[]>([])
  const [loading, setLoading] = useState(false)

  useEffect(() => {
    if (user) {
      loadTodaysPlans()
    }
  }, [user])

  async function loadTodaysPlans() {
    try {
      setLoading(true)
      const plans = await getTrainingPlans()
      setTodaysPlans(getTodaysPlans(plans))
    } catch {
      // Silently fail
    } finally {
      setLoading(false)
    }
  }

  const todayStr = new Date().toLocaleDateString('ko-KR', {
    month: 'long',
    day: 'numeric',
    weekday: 'short',
  })

  return (
    <Container maxWidth="sm">
      <Box sx={{ my: 4, textAlign: 'center' }}>
        {user ? (
          <>
            {/* Today's Training Section */}
            <Paper elevation={3} sx={{ p: 3, textAlign: 'left' }}>
              <Typography variant="h6" gutterBottom>
                📅 오늘의 훈련 ({todayStr})
              </Typography>
              {loading ? (
                <Box sx={{ display: 'flex', justifyContent: 'center', py: 2 }}>
                  <CircularProgress size={24} />
                </Box>
              ) : todaysPlans.length === 0 ? (
                <Typography color="text.secondary" sx={{ py: 2, textAlign: 'center' }}>
                  오늘 예정된 훈련이 없습니다
                </Typography>
              ) : (
                <List disablePadding>
                  {todaysPlans.map((plan) => (
                    <ListItem key={plan.id} disablePadding>
                      <ListItemButton
                        component={Link}
                        to={routes.executions.new.$({ planId: plan.id })}
                      >
                        <ListItemIcon>
                          <FitnessCenterIcon color="primary" />
                        </ListItemIcon>
                        <ListItemText
                          primary={plan.name}
                          secondary={`${plan.unit_amount} ${plan.unit_name}`}
                        />
                        <Chip
                          label={
                            plan.schedule_type === 'daily'
                              ? '매일'
                              : plan.schedule_days?.map(getWeekDayLabel).join(', ')
                          }
                          size="small"
                          variant="outlined"
                        />
                      </ListItemButton>
                    </ListItem>
                  ))}
                </List>
              )}
            </Paper>
          </>
        ) : (
          <Paper elevation={3} sx={{ p: 3, mt: 3 }}>
            <Typography variant="body1" sx={{ mb: 3 }}>
              시작하려면 로그인하세요
            </Typography>
            <LoginButton />
          </Paper>
        )}
      </Box>
    </Container>
  )
}
